function Navbar({ page, setPage, user, onLogout }) {
  const init = user ? `${user.first_name[0]}${user.last_name[0]}`.toUpperCase() : '';
  return (
    <nav className="nav">
      <div className="nav-inner">
        <div className="nav-logo" onClick={() => setPage('home')}>
          <span className="nav-dot" /><span>Orienta<span style={{ color: GOLD }}>GN</span></span>
        </div>
        <div className="nav-links">
          {[['home','OrientaBot','chat'],['universites','Universités','build'],['filieres','Filières','grid']].map(([k,l,ic]) => (
            <button key={k} className={`nb ${page===k?'active':''}`} onClick={() => setPage(k)}>
              <I n={ic} s={13}/> {l}
            </button>
          ))}
          {user?.is_staff && (
            <button className={`nb ${page==='admin'?'active':''}`} onClick={() => setPage('admin')}>
