  const handleSearch = () => {
    // Si l'utilisateur est connecté, on pourrait passer la requête au chatbot (via un state global).
    // Pour l'instant, on redirige vers le chatbot ou l'inscription.
    setPage(user ? 'chatbot' : 'inscription');
