                  <div key={ic} style={{ background:'#f8fafc',borderRadius:9,padding:'.65rem',textAlign:'center' }}>
                    <div style={{ fontSize:'.7rem',color:'#64748b',marginBottom:'.2rem' }}>{ic}</div>
                    <div style={{ fontWeight:700,fontSize:'.78rem',color:DARK }}>{v}</div>
                  </div>
                ))}
              </div>
              <div style={{ marginBottom:'.9rem' }}>
                <div className="sec-lbl">Description</div>
                <p style={{ fontSize:'.86rem',color:'#475569',lineHeight:1.6 }}>{modal.description}</p>
              </div>
              <div style={{ marginBottom:'.9rem' }}>
                <div className="sec-lbl">Débouchés</div>
                <ul style={{ listStyle:'none',display:'flex',flexDirection:'column',gap:'.35rem' }}>
                  {(modal.debouches||[]).map((d,i) => (
                    <li key={i} style={{ display:'flex',gap:'.5rem',fontSize:'.85rem',color:'#374151' }}>
                      <span style={{ color:G,flexShrink:0 }}>✓</span>{d}
                    </li>
                  ))}
                </ul>
              </div>
              {modal.cas_special && <div className="alert alert-ok"><I n="star" s={15} c="#166534"/><span><strong>Emploi quasi-garanti</strong> : WCRG, SMB Winning, Simandou.</span></div>}
              {modal.concours    && <div className="alert alert-warn"><I n="warn" s={15} c="#92400e"/><span><strong>Concours + Mention obligatoire.</strong> ~200 places.</span></div>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ════════════════ FILIÈRES ════════════════ */
function PageFilieres() {
  const [unis, setUnis]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [uniF, setUniF]   = useState('');
  const [search, setSearch] = useState('');
  const [modal, setModal]   = useState(null);

  useEffect(() => {
    dataAPI.universites().then(r => { setUnis(r.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  const all = unis.flatMap(u => (u.filieres||[]).map(f => ({ ...f, _uni:u, _moy:f.moyenne_requise })));
  const filtered = all.filter(f => {
    if (uniF && f._uni.id !== uniF) return false;
    if (search) { const q = search.toLowerCase(); return f.nom.toLowerCase().includes(q)||f._uni.sigle.toLowerCase().includes(q)||(f.debouches||'').toLowerCase().includes(q); }
    return true;
  });

  if (loading) return <div className="full-spin"><div className="spinner"/></div>;

  return (
    <div className="page">
      <div style={{ paddingTop:'1.5rem',marginBottom:'2rem' }}>
        <div className="sec-eyebrow">60+ formations</div>
        <h1 className="sec-title">Toutes les filières</h1>
        <p className="sec-sub">Filtre et recherche parmi toutes les filières des universités guinéennes.</p>
      </div>
      <div style={{ display:'flex',gap:'1rem',marginBottom:'1.25rem',flexWrap:'wrap',alignItems:'center' }}>
        <input className="fi" placeholder="🔍 Rechercher une filière, un débouché..." value={search} onChange={e => setSearch(e.target.value)} style={{ flex:1,minWidth:200 }}/>
        <div className="filter-bar" style={{ margin:0,flex:'none' }}>
          <span className={`chip ${!uniF?'active':''}`} onClick={() => setUniF('')}>Toutes</span>
          {unis.map(u => <span key={u.id} className={`chip ${uniF===u.id?'active':''}`} onClick={() => setUniF(u.id)}>{u.sigle}</span>)}
        </div>
      </div>
      <div style={{ color:'#64748b',fontSize:'.83rem',marginBottom:'.9rem' }}>{filtered.length} filière{filtered.length>1?'s':''} trouvée{filtered.length>1?'s':''}</div>
      <div className="fgrid">
        {filtered.map((f,i) => (
          <div key={i} className="fc" onClick={() => setModal(f)}>
            <div style={{ display:'flex',justifyContent:'space-between',marginBottom:'.5rem' }}>
              <span className={`badge ${uniBadge(f._uni.sigle)}`}>{f._uni.sigle}</span>
              <div style={{ display:'flex',gap:'.25rem' }}>
                {f.cas_special && <span className="badge bg-gold">⭐</span>}
                {f.concours    && <span className="badge bg-red">⚠️</span>}
              </div>
            </div>
            <h3 style={{ fontWeight:700,fontSize:'.9rem',color:DARK,marginBottom:'.35rem' }}>{f.nom}</h3>
            <p style={{ fontSize:'.78rem',color:'#64748b',lineHeight:1.4,marginBottom:'.6rem' }}>{(f.debouches||'').slice(0,80)}...</p>
            <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginTop:'auto' }}>
              <span style={{ fontSize:'.73rem',color:'#94a3b8' }}>{f.duree}</span>
              <span className="badge bg-green" style={{ fontSize:'.69rem' }}>≥{f._moy}/20</span>
            </div>
          </div>
        ))}
      </div>
      {modal && (
        <div className="modal-ov" onClick={() => setModal(null)}>
          <div className="modal-box" style={{ maxWidth:500 }} onClick={e => e.stopPropagation()}>
            <div className="modal-head" style={{ background:`linear-gradient(135deg,${DARK},${uniColor(modal._uni.id)})` }}>
              <h3 style={{ color:'#fff',fontWeight:700,fontSize:'1rem' }}>{modal.nom_complet||modal.nom}</h3>
              <button className="modal-close" onClick={() => setModal(null)}>✕</button>
            </div>
            <div className="modal-body" style={{ maxHeight:'60vh',overflowY:'auto' }}>
              <p style={{ fontSize:'.86rem',color:'#475569',lineHeight:1.6,marginBottom:'1rem' }}>{modal.description}</p>
              <div className="sec-lbl">Débouchés</div>
              <ul style={{ listStyle:'none',display:'flex',flexDirection:'column',gap:'.35rem',marginBottom:'1rem' }}>
                {(modal.debouches||[]).map((d,i) => <li key={i} style={{ display:'flex',gap:'.5rem',fontSize:'.84rem',color:'#374151' }}><span style={{ color:G }}>✓</span>{d}</li>)}
              </ul>
              {modal.cas_special && <div className="alert alert-ok"><I n="star" s={14} c="#166534"/><span><strong>Emploi garanti</strong> chez WCRG, SMB, Simandou.</span></div>}
              {modal.concours    && <div className="alert alert-warn"><I n="warn" s={14} c="#92400e"/><span><strong>Concours + Mention obligatoire.</strong></span></div>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ════════════════ CHATBOT ════════════════ */
function PageChatbot({ user }) {
  const [convs, setConvs]     = useState([]);
  const [curConv, setCurConv] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput]     = useState('');
  const [sending, setSending] = useState(false);
  const [guided, setGuided]   = useState(false);
  const [gStep, setGStep]     = useState(1);
  const [gData, setGData]     = useState({});
  const [recording, setRecording] = useState(false);
  const [dragOver, setDragOver]   = useState(false);
  const [uploadFile, setUploadFile] = useState(null);
  const bodyRef = useRef(null);
  const taRef   = useRef(null);
  const mediaRef = useRef(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    chatAPI.conversations().then(r => setConvs(r.data)).catch(() => {});
  }, []);

  useEffect(() => {
    if (bodyRef.current) bodyRef.current.scrollTop = bodyRef.current.scrollHeight;
  }, [messages, sending]);

  const loadConv = async id => {
    const { data } = await chatAPI.detail(id);
    setCurConv(data);
    setMessages(data.messages || []);
  };

  const newConv = async () => {
    const { data } = await chatAPI.create();
    setCurConv(data); setMessages([]);
    setConvs(p => [data, ...p]);
  };

  const delConv = async (id, e) => {
    e.stopPropagation();
    if (!window.confirm('Supprimer ?')) return;
    await chatAPI.delete(id);
    setConvs(p => p.filter(c => c.id !== id));
    if (curConv?.id === id) { setCurConv(null); setMessages([]); }
  };

  const send = async (text, file) => {
    const msg = text || input.trim();
    if (!msg && !file && !uploadFile) return;
    if (sending) return;
    setInput(''); setUploadFile(null);
    if (taRef.current) taRef.current.style.height = 'auto';
    setSending(true);

    const displayMsg = msg || (file ? `📎 Fichier : ${file.name}` : uploadFile ? `📎 Fichier : ${uploadFile.name}` : '');
    setMessages(p => [...p, { role:'user', contenu:displayMsg }]);

    try {
      const fd = new FormData();
      if (msg) fd.append('message', msg);
      if (curConv?.id) fd.append('conversation_id', curConv.id);
      const f = file || uploadFile;
      if (f) fd.append('fichier', f);

      const { data } = await chatAPI.sendForm(fd);
      setMessages(p => [...p, { role:'assistant', contenu:data.response }]);
      setCurConv({ id:data.conversation_id, titre:data.conversation_titre });
      setConvs(p => {
        const ex = p.find(c => c.id===data.conversation_id);
        if (ex) return p.map(c => c.id===data.conversation_id ? {...c,titre:data.conversation_titre}:c);
        return [{ id:data.conversation_id, titre:data.conversation_titre },...p];
      });
    } catch {
      setMessages(p => [...p, { role:'assistant', contenu:'❌ Erreur de connexion. Vérifiez que le serveur Django est démarré.' }]);
    }
    setSending(false);
  };

  /* Vocal */
  const toggleVocal = async () => {
    if (recording) {
      mediaRef.current?.stop();
      setRecording(false);
      return;
    }
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream);
      const chunks = [];
      mr.ondataavailable = e => chunks.push(e.data);
      mr.onstop = () => {
        const blob = new Blob(chunks, { type:'audio/webm' });
        // Speech-to-text simple via Web Speech API si dispo
        if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
          const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
          const rec = new SR();
          rec.lang = 'fr-FR';
          rec.onresult = e => { setInput(e.results[0][0].transcript); };
          rec.start();
        } else {
          setInput(p => p + ' [Message vocal enregistré — transcription non disponible dans ce navigateur]');
        }
        stream.getTracks().forEach(t => t.stop());
      };
      mr.start();
      mediaRef.current = mr;
      setRecording(true);
      setTimeout(() => { if (mediaRef.current?.state==='recording') { mediaRef.current.stop(); setRecording(false); } }, 30000);
    } catch { alert('Accès au microphone refusé.'); }
  };

  /* Drag & Drop */
  const handleDrop = e => {
    e.preventDefault(); setDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) setUploadFile(file);
  };

  const handleGuided = (key, val) => {
    const next = { ...gData, [key]: val };
    setGData(next);
    if (key==='bac') { setGStep(2); return; }
    if (key==='moy') { setGStep(3); return; }
    setGuided(false); setGStep(1); setGData({});
    send(`Orientation personnalisée. Mon bac : ${next.bac}. Ma moyenne : ${next.moy}/20. Domaine : ${val}. Quelles filières recommandes-tu dans les universités guinéennes ?`);
  };

  const init = `${user.first_name[0]}${user.last_name[0]}`.toUpperCase();
  const QUICK = [
    ['🎯 Mon profil', `Quelles filières pour bac ${user.serie_bac||'SE'} avec ${user.moyenne_bac||'13'}/20 ?`],
    ['🚂 Ferroviaire', "Institut de Chemin de Fer — emploi garanti ?"],
    ['💻 Informatique', "Filières informatiques disponibles ?"],
    ['🏥 Santé', "Comment accéder à la FSTS (Médecine) ?"],
    ['⛏️ Mines', "Institut des Mines et Géologie de Boké ?"],
    ['🌿 Environnement', "Filières environnement à N'Zérékoré ?"],
  ];

  return (
    <div className="chat-layout">
      {/* SIDEBAR */}
      <div className="chat-sb">
        <div className="chat-sb-top">
          <button className="btn btn-primary" style={{ width:'100%' }} onClick={newConv}>
            <I n="plus" s={15}/> Nouvelle conversation
          </button>
        </div>
        <div className="chat-list">
          {convs.length===0 && <p style={{ textAlign:'center',color:'#94a3b8',fontSize:'.8rem',marginTop:'2rem' }}>Aucune conversation</p>}
          {convs.map(c => (
            <div key={c.id} className={`ci ${curConv?.id===c.id?'active':''}`} onClick={() => loadConv(c.id)}>
              <div className="ci-title">{c.titre}</div>
              <button className="ci-del" onClick={e => delConv(c.id,e)}><I n="trash" s={12}/></button>
            </div>
          ))}
        </div>
        <div style={{ padding:'.9rem',borderTop:'1px solid #f1f5f9' }}>
          <div style={{ display:'flex',alignItems:'center',gap:'.55rem' }}>
            <div style={{ width:32,height:32,borderRadius:'50%',background:G,display:'flex',alignItems:'center',justifyContent:'center',color:'#fff',fontSize:'.72rem',fontWeight:700,flexShrink:0 }}>{init}</div>
            <div style={{ minWidth:0 }}>
              <div style={{ fontSize:'.81rem',fontWeight:600,color:DARK,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{user.first_name} {user.last_name}</div>
              <div style={{ fontSize:'.7rem',color:'#94a3b8' }}>{user.serie_bac||'—'} · {user.moyenne_bac||'?'}/20</div>
            </div>
          </div>
        </div>
      </div>

      {/* MAIN CHAT */}
      <div className="chat-main">
        <div className="chat-top">
          <div style={{ width:36,height:36,borderRadius:'50%',background:G,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
            <I n="robot" s={17} c="#fff"/>
          </div>
          <div>
            <div style={{ fontWeight:700,color:DARK,fontSize:'.92rem',display:'flex',alignItems:'center',gap:'.5rem' }}>
              OrientaBot <span style={{ background:'#22c55e',color:'#fff',fontSize:'.63rem',padding:'.15rem .5rem',borderRadius:50,fontWeight:700 }}>En ligne</span>
            </div>
            <div style={{ fontSize:'.75rem',color:'#64748b' }}>IA · 5 universités guinéennes</div>
          </div>
          <div style={{ marginLeft:'auto',display:'flex',gap:'.4rem' }}>
            <button className="btn btn-outline btn-sm" onClick={() => { setGuided(true); setGStep(1); setGData({}); }}>
              <I n="grid" s={13}/> Mode guidé
            </button>
          </div>
        </div>

        <div className="chat-body" ref={bodyRef}>
          {messages.length===0 && (
            <div className="mr">
              <div className="mav bot"><I n="robot" s={13} c="#fff"/></div>
              <div className="bub bot">
                Bonjour <strong>{user.first_name}</strong> ! 👋 Je suis <strong>OrientaBot</strong>, ton conseiller d'orientation académique pour les universités guinéennes.<br/><br/>
                {user.serie_bac && user.moyenne_bac ? (
                  <>J'ai ton profil : <strong>Bac {user.serie_bac}</strong>, moyenne <strong>{user.moyenne_bac}/20</strong>.<br/>Envoie-moi un message et je te donne tes recommandations personnalisées ! 🎯</>
                ) : user.serie_bac ? (
                  <>Je vois ton <strong>Bac {user.serie_bac}</strong>. Pour te conseiller précisément, quelle est ta <strong>moyenne au baccalauréat</strong> (sur 20) ?</>
                ) : (
                  <>Pour commencer, es-tu <strong>bachelier(ère)</strong> ?<br/><br/>
                  Si oui, dis-moi ta <strong>série de bac</strong> (SE, SE-FA, SM, SS, SS-FA) et ta <strong>moyenne</strong> — je te listerai toutes les filières accessibles dans les universités guinéennes. 🎓</>
                )}
              </div>
            </div>
          )}
          {messages.map((m,i) => (
            <div key={i} className={`mr ${m.role==='user'?'u':''}`}>
              <div className={`mav ${m.role==='user'?'usr':'bot'}`}>{m.role==='user'?init:<I n="robot" s={13} c="#fff"/>}</div>
              <div className={`bub ${m.role==='user'?'usr':'bot'}`} dangerouslySetInnerHTML={{ __html:md(m.contenu) }}/>
            </div>
          ))}
          {sending && (
            <div className="mr">
              <div className="mav bot"><I n="robot" s={13} c="#fff"/></div>
              <div className="typing"><div className="dot"/><div className="dot"/><div className="dot"/></div>
            </div>
          )}
        </div>

        <div className="chat-foot">
          {/* Fichier sélectionné */}
          {uploadFile && (
            <div style={{ display:'flex',alignItems:'center',gap:'.6rem',background:'#f0fdf4',border:'1px solid #bbf7d0',borderRadius:9,padding:'.5rem .85rem',marginBottom:'.6rem' }}>
              <I n="file" s={15} c={G}/>
              <span style={{ fontSize:'.82rem',color:'#166534',flex:1 }}>{uploadFile.name}</span>
              <button style={{ background:'none',border:'none',cursor:'pointer',color:'#94a3b8' }} onClick={() => setUploadFile(null)}>✕</button>
            </div>
          )}

          {/* Zone drag & drop */}
          <div
            className={`upload-zone ${dragOver?'drag':''}`}
            onDragOver={e => { e.preventDefault(); setDragOver(true); }}
            onDragLeave={() => setDragOver(false)}
            onDrop={handleDrop}
            onClick={() => fileInputRef.current?.click()}
          >
            <input ref={fileInputRef} type="file" accept=".txt,.pdf,.doc,.docx,.csv,.json" onChange={e => setUploadFile(e.target.files[0])} />
            <I n="upload" s={18} c="#94a3b8"/>
            <p style={{ fontSize:'.78rem',color:'#94a3b8',marginTop:'.3rem' }}>
              Glisse un fichier ici ou clique pour importer · Relevé de notes, CV, lettre...
            </p>
          </div>

          {/* Questions rapides */}
          <div className="qchips">
            {QUICK.map(([l,q]) => <button key={l} className="qc" onClick={() => send(q)}>{l}</button>)}
          </div>

          {/* Zone saisie */}
          <div className="input-row">
            <button
              className={`vocal-btn ${recording?'recording':''}`}
              onClick={toggleVocal}
              title={recording?'Arrêter':'Parler'}
            >
              <I n="mic" s={16} c={recording?'#fff':G}/>
            </button>
            <textarea
              ref={taRef}
              className="chat-ta"
              rows={1}
              placeholder={recording ? '🎤 Enregistrement en cours...' : 'Écris ta question... (Entrée pour envoyer)'}
              value={input}
              onChange={e => { setInput(e.target.value); e.target.style.height='auto'; e.target.style.height=Math.min(e.target.scrollHeight,110)+'px'; }}
              onKeyDown={e => { if (e.key==='Enter'&&!e.shiftKey) { e.preventDefault(); send(); } }}
              disabled={recording}
            />
            <button className="send-btn" disabled={sending||(!input.trim()&&!uploadFile)} onClick={() => send()}>
              <I n="send" s={15} c="#fff"/>
            </button>
          </div>
          {recording && <p style={{ textAlign:'center',fontSize:'.75rem',color:'#ef4444',marginTop:'.4rem' }}>🔴 Enregistrement... Cliquez sur le micro pour arrêter</p>}
        </div>
      </div>

      {/* Modal guidé */}
      {guided && (
        <div className="modal-ov" onClick={() => setGuided(false)}>
          <div className="modal-box" onClick={e => e.stopPropagation()}>
            <div className="modal-head">
              <div>
                <h3 style={{ color:'#fff',fontWeight:700 }}>🧭 Orientation guidée</h3>
                <p style={{ color:'rgba(255,255,255,.7)',fontSize:'.82rem' }}>Étape {gStep}/3</p>
              </div>
              <button className="modal-close" onClick={() => setGuided(false)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="progress-bar"><div className="progress-fill" style={{ width:`${(gStep/3)*100}%` }}/></div>
              {gStep===1 && <>
                <p style={{ fontWeight:700,color:DARK,marginBottom:'1rem',fontSize:'.9rem' }}>1. Quel est ton type de bac ?</p>
                {[['🔬','SE','Sciences Expérimentales'],['🔬','SE-FA','SE-FA'],['📐','SM','Sciences Mathématiques'],['📚','SS','Sciences Sociales'],['📚','SS-FA','SS-FA']].map(([ic,v,l]) => (
                  <button key={v} className="go" onClick={() => handleGuided('bac',v)}><span style={{ fontSize:'1.1rem' }}>{ic}</span>{v} — {l}</button>
                ))}
              </>}
              {gStep===2 && <>
                <p style={{ fontWeight:700,color:DARK,marginBottom:'1rem',fontSize:'.9rem' }}>2. Ta moyenne au bac ?</p>
                {['10 – 11/20','12 – 13/20','14 – 15/20','16/20 et plus 🌟'].map(v => (
                  <button key={v} className="go" onClick={() => handleGuided('moy',v)}><span style={{ fontSize:'1.1rem' }}>📊</span>{v}</button>
                ))}
              </>}
              {gStep===3 && <>
                <p style={{ fontWeight:700,color:DARK,marginBottom:'1rem',fontSize:'.9rem' }}>3. Quel domaine t'intéresse ?</p>
                {[['💻','Informatique & Numérique'],['⚙️','Génie & Ingénierie'],['🚂','Ferroviaire (emploi garanti !)'],['⛏️','Mines & Géologie'],['🌿','Environnement & Nature'],['🏥','Santé & Médecine'],['📚','Lettres & Sciences Sociales'],['💰','Économie & Gestion']].map(([ic,v]) => (
                  <button key={v} className="go" onClick={() => handleGuided('dom',v)}><span style={{ fontSize:'1.1rem' }}>{ic}</span>{v}</button>
                ))}
              </>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ════════════════ ADMIN DASHBOARD ════════════════ */
function PageAdmin({ user }) {
  const [data, setData]   = useState(null);
  const [loading, setLoading] = useState(true);
  const [tab, setTab]     = useState('overview');

  useEffect(() => {
    fetch('http://localhost:8000/api/admin-dashboard/', {
      headers: { 'Authorization': `Bearer ${localStorage.getItem('access_token')}` }
    }).then(r => r.json()).then(d => { setData(d); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (!user?.is_staff) return (
    <div className="page" style={{ textAlign:'center',paddingTop:'5rem' }}>
      <div style={{ fontSize:'3rem',marginBottom:'1rem' }}>🔒</div>
      <h2 style={{ color:DARK }}>Accès réservé aux administrateurs</h2>
    </div>
  );
  if (loading) return <div className="full-spin"><div className="spinner"/></div>;
  if (!data)   return <div className="page"><div className="alert alert-err">Erreur de chargement</div></div>;

  const maxBar = Math.max(...(data.bac_stats||[]).map(b=>b.count),1);
  const maxMsg = Math.max(...(data.msgs_par_jour||[]).map(d=>d.count),1);

  return (
    <div className="page" style={{ paddingTop:'2rem' }}>
      <div style={{ display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'2rem',flexWrap:'wrap',gap:'1rem' }}>
        <div>
          <div className="sec-eyebrow">Tableau de bord</div>
          <h1 className="sec-title">Administration OrientaGN</h1>
        </div>
        <div style={{ display:'flex',gap:'.5rem' }}>
          {[['overview','Vue globale'],['users','Étudiants'],['convs','Conversations'],['filieres','Filières']].map(([k,l]) => (
            <button key={k} className={`btn ${tab===k?'btn-primary':'btn-outline'} btn-sm`} onClick={() => setTab(k)}>{l}</button>
          ))}
        </div>
      </div>

      {tab==='overview' && <>
        {/* KPIs */}
        <div className="dash-grid">
          {[
            ['👥', data.total_users, 'Étudiants inscrits'],
            ['💬', data.total_convs, 'Conversations'],
            ['📨', data.total_msgs, 'Messages échangés'],
            ['🏛️', data.nb_universites, 'Universités'],
            ['📚', data.total_filieres, 'Filières'],
            ['🤖', `${data.taux_chatbot}%`, 'Taux utilisation chatbot'],
          ].map(([ic,v,l]) => (
            <div key={l} className="kpi">
              <div className="kpi-icon">{ic}</div>
              <div className="kpi-val">{v}</div>
              <div className="kpi-lbl">{l}</div>
            </div>
          ))}
        </div>

        <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:'1.5rem',marginBottom:'1.5rem' }}>
          {/* Messages par jour */}
          <div className="table-wrap">
            <div className="tw-head">📈 Messages par jour (7 derniers jours)</div>
            <div style={{ padding:'1rem 1.25rem' }}>
              <div className="msg-chart">
                {data.msgs_par_jour.map((d,i) => (
                  <div key={i} className="msg-bar" style={{ height:`${Math.max((d.count/maxMsg)*100,4)}%` }} title={`${d.count} messages`}>
                    <span className="msg-bar-lbl">{d.date}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Répartition séries BAC */}
          <div className="table-wrap">
            <div className="tw-head">🎓 Séries BAC des étudiants</div>
            <div className="bar-chart">
              {data.bac_stats.length===0 && <p style={{ color:'#94a3b8',fontSize:'.85rem' }}>Aucune donnée</p>}
              {data.bac_stats.map(b => (
                <div key={b.serie_bac} className="bar-row">
                  <span className="bar-lbl">{b.serie_bac}</span>
                  <div className="bar-track"><div className="bar-fill" style={{ width:`${(b.count/maxBar)*100}%` }}/></div>
                  <span className="bar-val">{b.count}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Inscrits récents */}
        <div className="table-wrap">
          <div className="tw-head">🕐 Dernières inscriptions</div>
          <div style={{ overflowX:'auto' }}>
            <table>
              <thead><tr><th>Étudiant</th><th>Username</th><th>Série BAC</th><th>Moyenne</th><th>Inscrit le</th></tr></thead>
              <tbody>
                {data.recent_users.map(u => (
                  <tr key={u.id}>
                    <td style={{ fontWeight:600 }}>{u.first_name} {u.last_name}</td>
                    <td style={{ color:'#64748b' }}>@{u.username}</td>
                    <td>{u.serie_bac ? <span className="badge bg-blue">{u.serie_bac}</span> : '—'}</td>
                    <td>{u.moyenne_bac ? <span className="badge bg-green">{u.moyenne_bac}/20</span> : '—'}</td>
                    <td style={{ color:'#64748b',fontSize:'.8rem' }}>{new Date(u.date_inscription).toLocaleDateString('fr-FR')}</td>
                  </tr>
                ))}
                {data.recent_users.length===0 && <tr><td colSpan={5} style={{ textAlign:'center',color:'#94a3b8',padding:'2rem' }}>Aucun utilisateur</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </>}

      {tab==='users' && (
        <div className="table-wrap">
          <div className="tw-head">👥 Étudiants inscrits ({data.total_users})</div>
          <div style={{ overflowX:'auto' }}>
            <table>
              <thead><tr><th>Nom</th><th>Username</th><th>Série BAC</th><th>Moyenne</th><th>N° PV</th><th>Inscrit le</th></tr></thead>
              <tbody>
                {data.recent_users.map(u => (
                  <tr key={u.id}>
                    <td style={{ fontWeight:600 }}>{u.first_name} {u.last_name}</td>
                    <td style={{ color:'#64748b' }}>@{u.username}</td>
                    <td>{u.serie_bac?<span className="badge bg-blue">{u.serie_bac}</span>:'—'}</td>
                    <td>{u.moyenne_bac?<span className="badge bg-green">{u.moyenne_bac}/20</span>:'—'}</td>
                    <td style={{ color:'#64748b',fontSize:'.82rem' }}>—</td>
                    <td style={{ color:'#64748b',fontSize:'.8rem' }}>{new Date(u.date_inscription).toLocaleDateString('fr-FR')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {tab==='convs' && (
        <div className="table-wrap">
          <div className="tw-head">💬 Conversations récentes ({data.total_convs})</div>
          <div style={{ overflowX:'auto' }}>
            <table>
              <thead><tr><th>Titre</th><th>Étudiant</th><th>Dernière activité</th></tr></thead>
              <tbody>
                {data.recent_convs.map(c => (
                  <tr key={c.id}>
                    <td style={{ maxWidth:280,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{c.titre}</td>
                    <td style={{ fontWeight:500 }}>{c.etudiant__first_name} {c.etudiant__last_name}</td>
                    <td style={{ color:'#64748b',fontSize:'.8rem' }}>{new Date(c.updated_at).toLocaleDateString('fr-FR',{hour:'2-digit',minute:'2-digit'})}</td>
                  </tr>
                ))}
                {data.recent_convs.length===0 && <tr><td colSpan={3} style={{ textAlign:'center',color:'#94a3b8',padding:'2rem' }}>Aucune conversation</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {tab==='filieres' && (
        <div>
          {/* Résumé par université */}
          <div className="dash-grid" style={{ marginBottom:'1.5rem' }}>
            {[{id:'uganc',sigle:'UGANC',nom:'UGANC',nb:17},{id:'uk',sigle:'UK',nom:'UK Kindia',nb:14},{id:'ul',sigle:'UL',nom:'UL Labé',nb:15},{id:'ujnk',sigle:'UJNK',nom:'UJNK Kankan',nb:18},{id:'uz',sigle:'UZ',nom:'UZ N\'Zérékoré',nb:15}].map(u => (
              <div key={u.id} className="kpi" style={{ borderLeft:`4px solid ${uniColor(u.sigle)}` }}>
                {UNI_IMAGES[u.sigle.toLowerCase()] && <img src={UNI_IMAGES[u.sigle.toLowerCase()]} alt={u.nom} style={{ width:'100%',height:70,objectFit:'cover',borderRadius:8,marginBottom:'.5rem' }} />}
                <div className="kpi-val" style={{ fontSize:'1.5rem' }}>{u.nb}</div>
                <div className="kpi-lbl">{u.nom}</div>
              </div>
            ))}
          </div>
          <div className="alert alert-info"><I n="info" s={15} c="#1e40af"/><span>Les filières sont gérées depuis <strong>knowledge_base.py</strong>. Total : {data.total_filieres} filières dans {data.nb_universites} universités.</span></div>
        </div>
      )}
    </div>
  );
}

/* ════════════════ INSCRIPTION ════════════════ */
function PageInscription({ setPage, onLogin }) {
  const [form, setForm] = useState({ first_name:'',last_name:'',username:'',email:'',serie_bac:'',moyenne_bac:'',numero_pv:'',mot_de_passe:'' });
  const [err, setErr]   = useState('');
  const [loading, setLoading] = useState(false);
  const set = (k,v) => setForm(p => ({ ...p,[k]:v }));

  const submit = async () => {
    if (!form.first_name||!form.last_name||!form.username||!form.mot_de_passe||!form.serie_bac) {
      setErr('Remplissez tous les champs obligatoires (*)'); return;
    }
    if (form.mot_de_passe.length < 6) { setErr('Le mot de passe doit faire au moins 6 caractères'); return; }
    setErr(''); setLoading(true);
    try {
      const payload = { ...form };
      if (!payload.moyenne_bac) delete payload.moyenne_bac;
      const { data } = await authAPI.inscription(payload);
      localStorage.setItem('access_token', data.access);
      localStorage.setItem('refresh_token', data.refresh);
      onLogin(data.user); setPage('home');
    } catch (e) {
      const errs = e.response?.data;
      if (errs) setErr(Object.values(errs).flat().join(' · '));
      else setErr('Erreur lors de l\'inscription. Vérifiez la connexion au serveur.');
    }
    setLoading(false);
  };

  return (
    <div className="page" style={{ paddingTop:'2.5rem',paddingBottom:'3rem' }}>
      <div className="form-wrap">
        <div style={{ textAlign:'center',marginBottom:'1.75rem' }}>
          <div style={{ width:54,height:54,borderRadius:'50%',background:`${G}15`,display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto .9rem' }}>
            <I n="user" s={22} c={G}/>
          </div>
          <h1 className="form-title">Créer mon compte</h1>
          <p className="form-sub">Rejoins OrientaGN pour des recommandations personnalisées</p>
        </div>
        {err && <div className="alert alert-err"><I n="x" s={15}/>  {err}</div>}

        <div className="sec-lbl">Informations personnelles</div>
        <div className="frow">
          <div className="fg"><label className="fl">Prénom <span>*</span></label><input className="fi" placeholder="Hadjiratou" value={form.first_name} onChange={e => set('first_name',e.target.value)}/></div>
          <div className="fg"><label className="fl">Nom <span>*</span></label><input className="fi" placeholder="Diallo" value={form.last_name} onChange={e => set('last_name',e.target.value)}/></div>
        </div>
        <div className="frow">
          <div className="fg"><label className="fl">Nom d'utilisateur <span>*</span></label><input className="fi" placeholder="diallo_hadji" value={form.username} onChange={e => set('username',e.target.value)}/></div>
          <div className="fg"><label className="fl">E-mail</label><input className="fi" type="email" placeholder="email@exemple.com" value={form.email} onChange={e => set('email',e.target.value)}/></div>
        </div>

        <div className="sec-lbl" style={{ marginTop:'.25rem' }}>Informations BAC</div>
        <div className="frow">
          <div className="fg">
            <label className="fl">Série BAC <span>*</span></label>
            <select className="fsel" value={form.serie_bac} onChange={e => set('serie_bac',e.target.value)}>
              <option value="">Choisir...</option>
              <option value="SM">SM — Sciences Mathématiques</option>
              <option value="SE">SE — Sciences Expérimentales</option>
              <option value="SE-FA">SE-FA — Sciences Expérimentales FA</option>
              <option value="SS">SS — Sciences Sociales</option>
              <option value="SS-FA">SS-FA — Sciences Sociales FA</option>
            </select>
          </div>
          <div className="fg"><label className="fl">Moyenne BAC</label><input className="fi" type="number" placeholder="13.5" min="0" max="20" step="0.5" value={form.moyenne_bac} onChange={e => set('moyenne_bac',e.target.value)}/></div>
        </div>
        <div className="fg">
          <label className="fl">Numéro PV du BAC</label>
          <input className="fi" placeholder="Ex: 0012345" value={form.numero_pv} onChange={e => set('numero_pv',e.target.value)}/>
          <span style={{ fontSize:'.75rem',color:'#94a3b8',display:'block',marginTop:'.25rem' }}>Le numéro figurant sur votre procès-verbal</span>
        </div>

        <div className="sec-lbl" style={{ marginTop:'.25rem' }}>Sécurité</div>
        <div className="fg">
          <label className="fl">Mot de passe <span>*</span></label>
          <input className="fi" type="password" placeholder="Minimum 6 caractères" value={form.mot_de_passe} onChange={e => set('mot_de_passe',e.target.value)} onKeyDown={e => e.key==='Enter'&&submit()}/>
        </div>

        <div className="alert alert-info" style={{ marginBottom:'1.1rem' }}>
          <I n="info" s={14} c="#1e40af"/>
          <span style={{ fontSize:'.82rem' }}>Ton profil (série BAC + moyenne) permet au chatbot de te proposer des recommandations personnalisées.</span>
        </div>

        <button className="btn btn-primary" style={{ width:'100%' }} onClick={submit} disabled={loading}>
          {loading ? 'Création...' : <><I n="check" s={15}/> Créer mon compte</>}
        </button>
        <div className="divider"><span>Déjà inscrit ?</span></div>
        <button className="btn btn-outline" style={{ width:'100%' }} onClick={() => setPage('connexion')}>Se connecter</button>
      </div>
    </div>
  );
}

/* ════════════════ CONNEXION ════════════════ */
function PageConnexion({ setPage, onLogin }) {
  const [form, setForm] = useState({ username:'',password:'' });
  const [err, setErr]   = useState('');
  const [loading, setLoading] = useState(false);

  const submit = async () => {
    if (!form.username||!form.password) { setErr('Remplissez tous les champs.'); return; }
    setErr(''); setLoading(true);
    try {
      const { data } = await authAPI.connexion(form);
      localStorage.setItem('access_token', data.access);
      localStorage.setItem('refresh_token', data.refresh);
      onLogin(data.user); setPage('home');
    } catch (e) {
      setErr(e.response?.data?.detail || "Nom d'utilisateur ou mot de passe incorrect.");
    }
    setLoading(false);
  };

  return (
    <div className="page" style={{ paddingTop:'4rem',paddingBottom:'4rem' }}>
      <div className="form-wrap" style={{ maxWidth:420 }}>
        <div style={{ textAlign:'center',marginBottom:'1.75rem' }}>
          <div style={{ fontSize:'2.5rem',marginBottom:'.75rem' }}>🎓</div>
          <h1 className="form-title">Bon retour !</h1>
          <p className="form-sub">Connecte-toi pour accéder à ton espace personnalisé</p>
        </div>
        {err && <div className="alert alert-err"><I n="x" s={14}/> {err}</div>}
        <div className="fg"><label className="fl">Nom d'utilisateur</label><input className="fi" placeholder="ton_username" value={form.username} onChange={e => setForm(p=>({...p,username:e.target.value}))} onKeyDown={e=>e.key==='Enter'&&submit()}/></div>
        <div className="fg"><label className="fl">Mot de passe</label><input className="fi" type="password" placeholder="••••••••" value={form.password} onChange={e => setForm(p=>({...p,password:e.target.value}))} onKeyDown={e=>e.key==='Enter'&&submit()}/></div>
        <button className="btn btn-primary" style={{ width:'100%',marginTop:'.5rem' }} onClick={submit} disabled={loading}>
          {loading ? 'Connexion...' : 'Se connecter'}
        </button>
        <div className="divider"><span>Pas encore de compte ?</span></div>
        <button className="btn btn-outline" style={{ width:'100%' }} onClick={() => setPage('inscription')}><I n="user" s={15}/> Créer mon compte</button>
      </div>
    </div>
  );
}

/* ════════════════ PROFIL ════════════════ */
function PageProfil({ user, onUpdate, setPage }) {
  const [form, setForm] = useState({ first_name:user.first_name, last_name:user.last_name, email:user.email||'', serie_bac:user.serie_bac||'', moyenne_bac:user.moyenne_bac||'', numero_pv:user.numero_pv||'' });
  const [msg, setMsg]   = useState('');
  const [loading, setLoading] = useState(false);
  const init = `${user.first_name[0]}${user.last_name[0]}`.toUpperCase();

  const save = async () => {
    setLoading(true);
    try {
      const p = { ...form }; if (!p.moyenne_bac) delete p.moyenne_bac;
      const { data } = await authAPI.updateProfil(p);
      onUpdate(data); setMsg('✅ Profil mis à jour !');
    } catch { setMsg('❌ Erreur lors de la mise à jour.'); }
    setLoading(false);
  };

  return (
    <div className="page" style={{ paddingTop:'2.5rem' }}>
      <div className="profil-card">
        <div style={{ textAlign:'center',marginBottom:'1.75rem' }}>
          <div className="profil-av">{init}</div>
          <h2 style={{ fontFamily:'Sora,sans-serif',fontWeight:800,color:DARK }}>{user.first_name} {user.last_name}</h2>
          <p style={{ color:'#64748b',fontSize:'.86rem' }}>@{user.username}</p>
          <div style={{ display:'flex',justifyContent:'center',gap:'.5rem',marginTop:'.5rem' }}>
            {user.serie_bac && <span className="badge bg-blue">{user.serie_bac}</span>}
            {user.moyenne_bac && <span className="badge bg-green">{user.moyenne_bac}/20</span>}
            {user.numero_pv && <span className="badge bg-gray">PV: {user.numero_pv}</span>}
          </div>
        </div>
        {msg && <div className={`alert ${msg.startsWith('✅')?'alert-ok':'alert-err'}`}>{msg}</div>}
        <div className="sec-lbl">Informations personnelles</div>
        <div className="frow"><div className="fg"><label className="fl">Prénom</label><input className="fi" value={form.first_name} onChange={e=>setForm(p=>({...p,first_name:e.target.value}))}/></div><div className="fg"><label className="fl">Nom</label><input className="fi" value={form.last_name} onChange={e=>setForm(p=>({...p,last_name:e.target.value}))}/></div></div>
        <div className="fg"><label className="fl">E-mail</label><input className="fi" type="email" value={form.email} onChange={e=>setForm(p=>({...p,email:e.target.value}))}/></div>
        <div className="sec-lbl" style={{ marginTop:'.25rem' }}>BAC</div>
        <div className="frow"><div className="fg"><label className="fl">Série BAC</label><select className="fsel" value={form.serie_bac} onChange={e=>setForm(p=>({...p,serie_bac:e.target.value}))}><option value="">—</option><option value="SM">SM</option><option value="SE">SE</option><option value="SE-FA">SE-FA</option><option value="SS">SS</option><option value="SS-FA">SS-FA</option></select></div><div className="fg"><label className="fl">Moyenne</label><input className="fi" type="number" min="0" max="20" step="0.5" value={form.moyenne_bac} onChange={e=>setForm(p=>({...p,moyenne_bac:e.target.value}))}/></div></div>
        <div className="fg"><label className="fl">Numéro PV du BAC</label><input className="fi" placeholder="0012345" value={form.numero_pv} onChange={e=>setForm(p=>({...p,numero_pv:e.target.value}))}/></div>
        <div style={{ display:'flex',gap:'.7rem',marginTop:'1rem' }}>
          <button className="btn btn-primary" style={{ flex:1 }} onClick={save} disabled={loading}>{loading?'Enregistrement...':<><I n="edit" s={14}/> Enregistrer</>}</button>
          <button className="btn btn-outline" onClick={() => setPage('chatbot')}><I n="chat" s={14}/> Chatbot</button>
        </div>
      </div>
    </div>
  );
}

/* ════════════════ APP ROOT ════════════════ */
export default function App() {
  const [page, setPage] = useState('home');
  const [user, setUser] = useState(null);
  const [checking, setChecking] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (token) {
      authAPI.profil()
        .then(r => setUser(r.data))
        .catch(() => localStorage.clear())
        .finally(() => setChecking(false));
    } else setChecking(false);
  }, []);

  const guard = p => {
    if ((p==='chatbot'||p==='profil'||p==='admin') && !user) { setPage('connexion'); return; }
    setPage(p);
  };

  const handleLogin  = u => setUser(u);
  const handleLogout = () => { localStorage.clear(); setUser(null); setPage('home'); };
  const handleUpdate = u => setUser(u);

  if (checking) return <><style>{CSS}</style><div className="full-spin"><div className="spinner"/></div></>;

  return (
    <>
      <style>{CSS}</style>
      <Navbar page={page} setPage={guard} user={user} onLogout={handleLogout}/>
      {page==='home'        && <PageHome      setPage={guard} user={user}/>}
      {page==='universites' && <PageUniversites/>}
      {page==='filieres'    && <PageFilieres/>}
      {page==='chatbot'     && user && <PageChatbot user={user}/>}
      {page==='admin'       && <PageAdmin user={user}/>}
      {page==='inscription' && <PageInscription setPage={setPage} onLogin={handleLogin}/>}
      {page==='connexion'   && <PageConnexion   setPage={setPage} onLogin={handleLogin}/>}
      {page==='profil'      && user && <PageProfil user={user} onUpdate={handleUpdate} setPage={guard}/>}
    </>
  );
}
